$(document).ready(function() {
    var baseUrl = window.location.origin;
    let retrive_data = baseUrl+'/view_poja_ajax';
    let edit_category = baseUrl+'/master/pooja/edit_pooja';
  
    // Initialize DataTable
    $('#view_pooja').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,
        
        columnDefs: [{
            "defaultContent": "-",
            "targets": 0,
            "render": function (data, type, row, meta) {
              // Return the serial number (row index + 1)
              return meta.row + 1;
            }
          }],
        ajax: {
            url: retrive_data,
        },

        "columns": [
            { "data": null }, // This column will be used for serial numbers
             
            { 
              "data": "pooja_name",  
            },
            { 
              "data": "amount",
            },
            { 
              "data": "category_name",
            },
            { 
              "data": "subcategory_name",
            },
          { 
            title: 'Action',
            render: function(data, type, full) {
                return `
                <a href='edit_pooja/${full.id}'><i class="ti-pencil-alt"></i></a>
                 `;      
            }
        }

        ]
    });
});